import{j as e,L as t}from"./index-ixzp0WJG.js";/* empty css               */const s=()=>e.jsxs("div",{children:[e.jsx(t,{to:"/levels",className:"backButton level-theme-courage",children:"Back"}),e.jsxs("div",{className:"aLevelContainer level-theme-courage",children:[e.jsx("h1",{children:"Courage"}),e.jsx("p",{children:"Level of empowerment. Zone of exploration, accomplishment, fortitude, determination."}),e.jsx("p",{children:"Life is seen as exciting, challenging, and stimulating."}),e.jsx("p",{children:"Courage implies the willingness to try new things and to deal with the vicissitudes of life. One is able to cope with and effectively handle the opportunities of life. There is the capacity to face fears and to grow despite any perceived defects. Obstacles that defeat people whose consciousness level is below 200 act as stimulants to those who have evolved into courage."}),e.jsx("p",{children:"Crossing over level 200 is the most critical step in the evolution of human consciousness. There is intuitive acceptance of the truth of accountability as a spiritual and social reality. Truth is now seen as an ally instead of an enemy. Alignment with truth rather than gain brings strength, self-respect, and true empowerment rather than ego inflation."}),e.jsx("p",{children:'"What gains a man to win the world but lose his soul?"'}),e.jsx("p",{children:"Courage brings inner confidence and a greater sense of personal power because it is not dependent on external factors or results. To choose integrity and self-honesty is self-rewarding and reinforcing."}),e.jsx("p",{children:"There is a greater sense of inner freedom due to the relief from guilt and fear. Steadfastness and integrous performance result in inner gratifications that accrue from the satisfactory fulfillment of inner standards."}),e.jsx("p",{children:"At this level, it is the effort and intention, not just the result, that are important."}),e.jsx("p",{children:"The long-term goal of life becomes the development of inner potentials, such as strength, rather than the acquisition of externals."}),e.jsx("p",{children:"Although courage is both recognised and rewarded by society, social approval becomes only secondary. Temptations to violate integrity for gain are recognised and rejected."}),e.jsx("p",{children:"From consciousness calibration research, it is verified that everyone knows unconsciously when they are being lied to, which is revealed by the muscle test that instantly discerns truth from falsehood. This weakening of the body’s musculature response and the alterations of the energy flow through the acupuncture system indicate that the awareness of the difference between truth and falsehood is intrinsic to life energy and is reflected in the body’s response, even if the mind denies it."}),e.jsx("p",{children:"Self-honesty brings relief from the negative emotions of lower energy fields. Negative emotions are now unwelcome and unpleasant in both oneself and others. Argument, conflict, and discord are no longer attractive because they have lost their ego appeal."}),e.jsx("p",{children:"Transitory difficulties of social realities are accepted aspects of human life rather than being seen as personal insults. There is a progressive distaste for violence and the theatrics of political and ideological extremism, as the comfort of inner calm is preferred to the excitement of adrenaline."}),e.jsx("p",{children:"With maturity, there is the development of a sense of humor that replaces hostile attacks and outbursts. The peace and quiet that seem boring to lower levels of consciousness are now preferred, as are periods of calm during which to think and contemplate."}),e.jsx("p",{children:"Reflection now becomes more important than emotionalized reactivity."}),e.jsx("p",{children:"Desires are less demanding, and the quality of patience replaces drivenness and intolerance for delayed gratification."}),e.jsx("p",{children:"Personal happiness becomes an achievable goal, and gratitude replaces resentment, self-pity, and blaming others."}),e.jsx("p",{children:"The subjective experience of the world changes for the better, and people seem more friendly and hospitable."}),e.jsx("p",{children:"Courage leads to exploration and self-development, and it facilitates personal growth and the evolution of consciousness."}),e.jsx("p",{children:'The critical key to moving into the strength of courage is the acceptance of personal responsibility and accountability. This major move requires personal relinquishment of a victim/perpetrator dualistic fallacy that socially undermines integrity via blame, by which an external "cause" or social condition replaces integrous personal autonomy and self-honesty.'}),e.jsx("p",{children:"Courage doesn't mean absence of fear, but the willingness to surmount it, which—when accomplished—reveals hidden strength and the capacity for fortitude."})]})]});export{s as default};
